using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: The Cosmos provider now uses "$type"
        // as the discriminator property name instead of "Discriminator".
        // Existing documents already store "Discriminator", so we must
        // explicitly configure the old name to avoid data mismatches.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string Category { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

class CosmosQueryService
{
    // EF Core 9 breaking change: Synchronous I/O on the Cosmos provider
    // now throws by default. All queries must use async APIs.
    //
    // Before (EF Core 8 – sync, now throws):
    //   var products = db.Products.ToList();
    //   var first    = db.Products.First(p => p.Category == "Books");
    //   var count    = db.Products.Count();
    //
    // After (EF Core 9 – async):
    async Task<List<Product>> GetAllAsync(CosmosDbContext db) =>
        await db.Products.ToListAsync();

    async Task<Product> GetFirstBookAsync(CosmosDbContext db) =>
        await db.Products.FirstAsync(p => p.Category == "Books");

    async Task<int> CountAsync(CosmosDbContext db) =>
        await db.Products.CountAsync();
}

